import { defineCollection, reference, z } from 'astro:content';
import { glob } from 'astro/loaders';

const edition = z.object({
  format: z.enum(['ebook', 'paperback', 'hardcover', 'audiobook']),
  isbn: z.string().optional(),
  asin: z.string().optional(),
  retailer: z.string(),          // e.g. 'Amazon', 'Kobo', 'Apple Books'
  url: z.string().url(),          // buy link lives on the EDITION, not the work
  price: z.string().optional(),
  currency: z.string().default('USD'),
});

const comp = z.object({
  name: z.string(),
  // REQUIRED descriptive hook — never a bare name. Discipline borrowed from the
  // Andromeda GEO comp skill, but note THIS is public answer-engine JSON-LD.
  hook: z.string().min(20, 'Comps need a descriptive hook, not a bare name.'),
  sameAs: z.array(z.string().url()).optional(), // Wikidata/Goodreads to disambiguate the real entity
});

const author = defineCollection({
  loader: glob({ pattern: '**/*.{md,yaml}', base: './src/content/author' }),
  schema: ({ image }) => z.object({
    name: z.string(),
    alternateName: z.array(z.string()).optional(),
    bio: z.string(),
    photo: image().optional(),
    url: z.string().url(),
    sameAs: z.array(z.string().url()).default([]), // socials, Wikidata, Goodreads author page
    email: z.string().email().optional(),
  }),
});

const books = defineCollection({
  loader: glob({ pattern: '**/*.{md,mdx}', base: './src/content/books' }),
  schema: ({ image }) => z.object({
    title: z.string(),
    subtitle: z.string().optional(),
    slug: z.string(),
    description: z.string().min(1),      // required — the blurb
    cover: image(),                       // required — no book ships coverless
    author: reference('author'),
    series: reference('series').optional(),
    seriesPosition: z.number().optional(),
    datePublished: z.coerce.date(),
    language: z.string().default('en'),
    genres: z.array(z.string()).default([]),
    editions: z.array(edition).min(1),   // required — at least one buy link
    comps: z.array(comp).default([]),     // inline only; rendered on the book page
  }),
});

const series = defineCollection({
  loader: glob({ pattern: '**/*.{md,yaml}', base: './src/content/series' }),
  schema: ({ image }) => z.object({
    name: z.string(),
    slug: z.string(),
    description: z.string(),
    cover: image().optional(),
    author: reference('author'),
    // book membership + order derived from books' series/seriesPosition (isPartOf/hasPart)
    comps: z.array(comp).default([]),
  }),
});

const hubs = defineCollection({
  loader: glob({ pattern: '**/*.{md,yaml}', base: './src/content/hubs' }),
  schema: () => z.object({
    name: z.string(),                     // e.g. 'Human-AI Partnership'
    slug: z.string(),
    description: z.string(),
    // DefinedTerm(s) this hub is ABOUT — becomes CollectionPage.about
    about: z.array(z.object({ term: z.string(), sameAs: z.string().url().optional() })).min(1),
    // ordered book membership -> mainEntity: ItemList of positioned entries
    books: z.array(reference('books')).min(1),
    comps: z.array(comp).default([]),
  }),
});

const events = defineCollection({
  loader: glob({ pattern: '**/*.{md,yaml}', base: './src/content/events' }),
  schema: () => z.object({
    name: z.string(),
    slug: z.string(),
    description: z.string(),
    startDate: z.coerce.date(),
    endDate: z.coerce.date().optional(),
    location: z.string().optional(),
    url: z.string().url().optional(),
    eventAttendanceMode: z.enum(['online', 'offline', 'mixed']).default('offline'),
  }),
});

export const collections = { author, books, series, hubs, events };

// The single seam between the two tiers. Templates + JSON-LD depend ONLY on this.
// Tier 1 implements it with astro:content (FileSource). Tier 2 implements it with D1 (D1Source).
export interface Author { name: string; bio: string; url: string; sameAs: string[]; photo?: string; alternateName?: string[]; email?: string; }
export interface Edition { format: string; isbn?: string; asin?: string; retailer: string; url: string; price?: string; currency: string; }
export interface Comp { name: string; hook: string; sameAs?: string[]; }
export interface Book { title: string; subtitle?: string; slug: string; description: string; cover: string; datePublished: Date; language: string; genres: string[]; editions: Edition[]; comps: Comp[]; seriesSlug?: string; seriesPosition?: number; }
export interface Series { name: string; slug: string; description: string; cover?: string; comps: Comp[]; }
export interface Hub { name: string; slug: string; description: string; about: { term: string; sameAs?: string }[]; bookSlugs: string[]; comps: Comp[]; }
export interface EventItem { name: string; slug: string; description: string; startDate: Date; endDate?: Date; location?: string; url?: string; eventAttendanceMode: string; }

export interface ContentSource {
  getAuthor(): Promise<Author>;
  getBooks(): Promise<Book[]>;
  getBook(slug: string): Promise<Book | undefined>;
  getSeries(): Promise<Series[]>;
  getSeriesBySlug(slug: string): Promise<Series | undefined>;
  getHubs(): Promise<Hub[]>;
  getHub(slug: string): Promise<Hub | undefined>;
  getEvents(): Promise<EventItem[]>;
}

// Builds schema.org JSON-LD as ONE @graph with stable @ids so entities cross-reference
// instead of duplicating. Derived from ContentSource -> can't drift from visible content.
import type { Author, Book, Series, Hub } from './ContentSource';

const SITE = (path = '') => new URL(path, import.meta.env.SITE).toString();
export const authorId = () => SITE('#author');
export const bookId = (slug: string) => SITE(`/books/${slug}#book`);
export const seriesId = (slug: string) => SITE(`/series/${slug}#series`);

export function authorNode(a: Author) {
  return { '@type': 'Person', '@id': authorId(), name: a.name,
    alternateName: a.alternateName, description: a.bio, url: a.url,
    image: a.photo, sameAs: a.sameAs };
}

export function bookNode(b: Book, opts: { seriesSlug?: string } = {}) {
  return { '@type': 'Book', '@id': bookId(b.slug), name: b.title,
    ...(b.subtitle ? { alternateName: b.subtitle } : {}),
    author: { '@id': authorId() }, description: b.description,
    inLanguage: b.language, datePublished: b.datePublished.toISOString().slice(0, 10),
    genre: b.genres, image: b.cover,
    ...(opts.seriesSlug ? { isPartOf: { '@id': seriesId(opts.seriesSlug) },
         position: b.seriesPosition } : {}),
    workExample: b.editions.map((e) => ({ '@type': 'Book', bookFormat: e.format,
      isbn: e.isbn, potentialAction: undefined,
      offers: { '@type': 'Offer', url: e.url, price: e.price, priceCurrency: e.currency,
        availability: 'https://schema.org/InStock' } })) };
}

export function seriesNode(s: Series, memberIds: string[]) {
  return { '@type': 'BookSeries', '@id': seriesId(s.slug), name: s.name,
    description: s.description, author: { '@id': authorId() },
    hasPart: memberIds.map((id) => ({ '@id': id })) };
}

// Hub = CollectionPage.about[DefinedTerm] + mainEntity: ItemList of positioned books.
// Confirmed from live aeon14.com/themes pattern.
export function hubGraph(h: Hub, memberIds: string[]) {
  return { '@type': 'CollectionPage', name: h.name, description: h.description,
    about: h.about.map((t) => ({ '@type': 'DefinedTerm', name: t.term, sameAs: t.sameAs })),
    mainEntity: { '@type': 'ItemList', numberOfItems: memberIds.length,
      itemListElement: memberIds.map((id, i) => ({ '@type': 'ListItem',
        position: i + 1, item: { '@id': id } })) } };
}

export function graph(nodes: unknown[]) {
  return { '@context': 'https://schema.org', '@graph': nodes };
}

// MailerLite adapter. API key comes from the Pages Function env (never client-side).
import type { LeadAdapter, Lead } from './types';
export const mailerlite = (apiKey: string): LeadAdapter => ({
  name: 'mailerlite',
  async subscribe(lead: Lead) {
    const res = await fetch('https://connect.mailerlite.com/api/subscribers', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${apiKey}` },
      body: JSON.stringify({ email: lead.email, fields: { name: lead.name },
        groups: lead.groups }),
    });
    if (!res.ok) throw new Error(`MailerLite ${res.status}: ${await res.text()}`);
    return { ok: true };
  },
});

// EmailOctopus adapter. API key + list id from the Pages Function env.
import type { LeadAdapter, Lead } from './types';
export const emailoctopus = (apiKey: string, listId: string): LeadAdapter => ({
  name: 'emailoctopus',
  async subscribe(lead: Lead) {
    const res = await fetch(`https://api.emailoctopus.com/lists/${listId}/contacts`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${apiKey}` },
      body: JSON.stringify({ email_address: lead.email,
        fields: { FirstName: lead.name }, status: 'PENDING' }),
    });
    if (!res.ok) throw new Error(`EmailOctopus ${res.status}: ${await res.text()}`);
    return { ok: true };
  },
});

// POST /api/subscribe — server-side lead capture. Key never reaches the client.
// Opt-in mode is a CONFIG OPTION (single vs double). Turnstile + honeypot for spam.
import type { APIRoute } from 'astro';
import { env } from 'cloudflare:workers'; // current @astrojs/cloudflare env access (verified v7; replaced the removed Astro.locals.runtime.env)
import { mailerlite } from '../../lib/leads/mailerlite';
import { emailoctopus } from '../../lib/leads/emailoctopus';
import { siteConfig } from '../../config';

export const prerender = false;

export const POST: APIRoute = async ({ request }) => {
  const form = await request.formData();
  if (form.get('company')) return new Response(null, { status: 204 }); // honeypot
  const email = String(form.get('email') || '');
  const name = form.get('name') ? String(form.get('name')) : undefined;
  if (!email) return new Response(JSON.stringify({ error: 'email required' }), { status: 400 });

  const adapter = siteConfig.leads.provider === 'emailoctopus'
    ? emailoctopus((env as any).EMAILOCTOPUS_API_KEY, (env as any).EMAILOCTOPUS_LIST_ID)
    : mailerlite((env as any).MAILERLITE_API_KEY);

  // NOTE: single vs double opt-in is enforced by ESP config + siteConfig.leads.doubleOptIn.
  try {
    await adapter.subscribe({ email, name, groups: siteConfig.leads.groups });
    return new Response(JSON.stringify({ ok: true }), { status: 200 });
  } catch (e) {
    return new Response(JSON.stringify({ error: 'subscribe failed' }), { status: 502 });
  }
};

// The ONE file a cloning author edits for behavior (content lives in src/content).
export const siteConfig = {
  siteUrl: 'https://example.com',
  leads: {
    provider: 'mailerlite' as 'mailerlite' | 'emailoctopus',
    doubleOptIn: true,        // config option — single vs double opt-in
    groups: [] as string[],
  },
};
